import xml.etree.ElementTree as ET
from io import BytesIO

def validate_xml(xml_data):
    try:
        root = ET.parse(BytesIO(xml_data)).getroot()
        
        # Validate XML structure
        if root.tag != 'document':
            return False
        
        for child in root:
            if child.tag not in ['title', 'description']:
                return False
        
        # Validate XML content (e.g., check for empty strings)
        title = root.find('title').text.strip()
        description = root.find('description').text.strip()
        
        if not title or not description:
            return False
        
        return True
    
    except ET.ParseError:
        return False

# Example usage
xml_data = b'''<document>
                <title>Hello World</title>
                <description>This is a sample XML document.</description>
              </document>'''

if validate_xml(xml_data):
    print("XML document is valid.")
else:
    print("XML document is invalid or malformed.")